2250 |             try { ops = JSON.parse(ops); } catch(e) { return { content, success: false, logs: ["Invalid JSON"]}; }
2251 |         }
2252 | 
2253 |         ops.forEach(op => {
2254 |             if (op.action === 'comment') return;
2255 |             if (op.action === 'create_file') { lines = op.content.split('\n'); logs.push('Created file'); return; }
2256 |             
2257 |             if (op.action === 'replace_block') {
2258 |                 // Strategy 1: Exact String Match (Fastest)
2259 |                 const currentStr = lines.join('\n');
2260 |                 if (currentStr.includes(op.find_block)) {
2261 |                     lines = currentStr.replace(op.find_block, op.replace_with).split('\n');
2262 |                     logs.push('Exact match applied');
2263 |                     return;
2264 |                 }
2265 | 
2266 |                 // Strategy 2: Line-by-Line Fuzzy Match (Whitespace Agnostic)
2267 |                 const searchLines = op.find_block.split('\n').map(l => l.trim()).filter(l => l !== '');
2268 |                 if (searchLines.length === 0) return;
2269 | 
2270 |                 let matchStart = -1;
2271 |                 let matchEnd = -1;
2272 | 
2273 |                 // Scan file lines
2274 |                 for (let i = 0; i < lines.length; i++) {
2275 |                     // If first line matches (ignoring whitespace)
2276 |                     if (lines[i].trim() === searchLines[0]) {
2277 |                         // Check subsequent lines
2278 |                         let allMatch = true;
2279 |                         let fileOffset = 0;
2280 |                         let searchOffset = 1;
2281 |                         
2282 |                         while (searchOffset < searchLines.length) {
2283 |                             if (i + fileOffset + 1 >= lines.length) { allMatch = false; break; }
2284 |                             const nextFile = lines[i + fileOffset + 1].trim();
2285 |                             // Skip empty lines in file if they aren't in search block
2286 |                             if (nextFile === '') {
2287 |                                 fileOffset++;
2288 |                                 continue;
2289 |                             }
2290 |                             if (nextFile !== searchLines[searchOffset]) {
2291 |                                 allMatch = false;
2292 |                                 break;
2293 |                             }
2294 |                             fileOffset++;
2295 |                             searchOffset++;
2296 |                         }
2297 | 
2298 |                         if (allMatch) {
2299 |                             matchStart = i;
2300 |                             matchEnd = i + fileOffset;
2301 |                             break;
2302 |                         }
2303 |                     }
2304 |                 }
2305 | 
2306 |                 if (matchStart !== -1) {
2307 |                     // Replace the range of lines
2308 |                     const replacement = op.replace_with.split('\n');
2309 |                     lines.splice(matchStart, (matchEnd - matchStart) + 1, ...replacement);
2310 |                     logs.push(`Fuzzy match applied (Lines ${matchStart+1}-${matchEnd+1})`);
2311 |                 } else {
2312 |                     success = false;
2313 |                     logs.push(`Failed to find block: "${op.find_block.substring(0, 30)}..."`);
2314 |                     console.warn("Patch Mismatch. File has:", content.substring(0, 200), "... vs Search:", op.find_block);
2315 |                 }
2316 |             }
2317 |         });
2318 |         return { content: lines.join('\n'), success, logs };
2319 |     }
