5151 |     function formatBytes(bytes) {
5152 |         if (!bytes) return '0 B';
5153 |         const k = 1024;
5154 |         const sizes = ['B', 'KB', 'MB', 'GB'];
5155 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
5156 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
5157 |     }
