5159 |     function timeAgo(dateString) {
5160 |         const date = new Date(dateString);
5161 |         const now = new Date();
5162 |         const seconds = Math.floor((now - date) / 1000);
5163 |         if (seconds < 10) return 'just now';
5164 |         if (seconds < 60) return seconds + 's ago';
5165 |         const minutes = Math.floor(seconds / 60);
5166 |         if (minutes < 60) return minutes + 'm ago';
5167 |         const hours = Math.floor(minutes / 60);
5168 |         if (hours < 24) return hours + 'h ago';
5169 |         return date.toLocaleDateString();
5170 |     }
