5372 |     async function jumpToElement(selector, tabId, navIndex, loadMoreFn) {
5373 |         console.group(`[DeepJump] Target: ${selector} in ${tabId}`);
5374 |         
5375 |         const navItems = document.querySelectorAll('.nav-item');
5376 |         switchTab(tabId, navItems[navIndex]);
5377 | 
5378 |         const scrollContainer = document.querySelector('.main-view');
5379 |         let retryCount = 0;
5380 |         const MAX_RETRIES = 5;
5381 | 
5382 |         const attemptNavigation = async () => {
5383 |             const element = document.querySelector(selector);
5384 |             
5385 |             if (element) {
5386 |                 console.log("[DeepJump] Element found. Scrolling...");
5387 |                 
5388 |                 // Wait for any tab transition animations
5389 |                 await new Promise(r => setTimeout(r, 300));
5390 | 
5391 |                 let offsetTop = 0;
5392 |                 let curr = element;
5393 |                 while (curr && curr !== scrollContainer) {
5394 |                     offsetTop += curr.offsetTop;
5395 |                     curr = curr.offsetParent;
5396 |                 }
5397 | 
5398 |                 const targetScroll = offsetTop - (scrollContainer.clientHeight / 2) + (element.clientHeight / 2);
5399 |                 scrollContainer.scrollTo({ top: targetScroll, behavior: 'smooth' });
5400 | 
5401 |                 // Visual Highlight
5402 |                 element.style.transition = 'all 0.5s ease';
5403 |                 element.style.backgroundColor = 'rgba(59, 130, 246, 0.3)';
5404 |                 element.style.boxShadow = '0 0 30px rgba(59, 130, 246, 0.6)';
5405 |                 setTimeout(() => {
5406 |                     element.style.backgroundColor = '';
5407 |                     element.style.boxShadow = '';
5408 |                 }, 3000);
5409 |                 
5410 |                 console.groupEnd();
5411 |                 return true;
5412 |             }
5413 | 
5414 |             if (retryCount < MAX_RETRIES && loadMoreFn) {
5415 |                 console.log(`[DeepJump] Not found. Triggering loadMore (Attempt ${retryCount + 1})...`);
5416 |                 retryCount++;
5417 |                 showGlobalToast("🔍 Searching deeper...");
5418 |                 
5419 |                 await loadMoreFn(); 
5420 |                 await new Promise(r => setTimeout(r, 800)); // Wait for render
5421 |                 return attemptNavigation();
5422 |             }
5423 | 
5424 |             console.error("[DeepJump] Failed: Element not found after retries.");
5425 |             showGlobalToast("Entry not found in recent history.", true);
5426 |             console.groupEnd();
5427 |             return false;
5428 |         };
5429 | 
5430 |         setTimeout(attemptNavigation, 100);
5431 |     }
