6427 |     async function handleImportFileSelect(input) {
6428 |         const file = input.files[0];
6429 |         if (!file) return;
6430 |         
6431 |         const toast = document.createElement('div');
6432 |         toast.innerText = "Parsing " + file.name + "...";
6433 |         toast.style.cssText = "position:fixed; bottom:100px; left:50%; transform:translateX(-50%); background:#333; color:white; padding:10px 20px; border-radius:30px; z-index:9999;";
6434 |         document.body.appendChild(toast);
6435 | 
6436 |         pendingImportFiles = [];
6437 | 
6438 |         try {
6439 |             if (file.name.endsWith('.zip')) {
6440 |                 const zip = await JSZip.loadAsync(file);
6441 |                 const promises = [];
6442 |                 zip.forEach((relativePath, zipEntry) => {
6443 |                     if (!zipEntry.dir) {
6444 |                         promises.push(zipEntry.async("string").then(content => {
6445 |                             pendingImportFiles.push({ path: relativePath, content: content });
6446 |                         }));
6447 |                     }
6448 |                 });
6449 |                 await Promise.all(promises);
6450 |             } 
6451 |             else if (file.name.endsWith('.txt')) {
6452 |                 const text = await file.text();
6453 |                 // Parse "FILE: path\nContent" format
6454 |                 // Split by "\n\nFILE: " to handle multiple files, assuming double newline separator from export
6455 |                 const chunks = text.split(/\n\nFILE: /g);
6456 |                 
6457 |                 chunks.forEach((chunk, index) => {
6458 |                     // Handle first chunk edge case if it starts with "FILE: "
6459 |                     let cleanChunk = chunk;
6460 |                     if (index === 0 && chunk.startsWith("FILE: ")) cleanChunk = chunk.substring(6);
6461 |                     
6462 |                     const firstLineEnd = cleanChunk.indexOf('\n');
6463 |                     if (firstLineEnd !== -1) {
6464 |                         const path = cleanChunk.substring(0, firstLineEnd).trim();
6465 |                         const content = cleanChunk.substring(firstLineEnd + 1);
6466 |                         if (path) pendingImportFiles.push({ path, content });
6467 |                     }
6468 |                 });
6469 |             } 
6470 |             else {
6471 |                 throw new Error("Unsupported file format. Use .zip or .txt exported from Conduit.");
6472 |             }
6473 | 
6474 |             toast.remove();
6475 |             document.getElementById('import-count').innerText = `${pendingImportFiles.length} files extracted.`;
6476 |             document.getElementById('import-target-repo').value = CONFIG.repoName;
6477 |             document.getElementById('import-target-folder').value = "";
6478 |             document.getElementById('import-modal').style.display = 'flex';
6479 | 
6480 |         } catch (e) {
6481 |             toast.remove();
6482 |             alert("Parse Error: " + e.message);
6483 |         }
6484 |         
6485 |         input.value = ''; // Reset input
6486 |     }
