7765 |     function extractTableNames(sql) {
7766 |         if (!sql) return [];
7767 |         const tables = [];
7768 |         const systemNoise = ['columns', 'tables', 'schemata', 'information_schema'];
7769 |         
7770 |         // Pattern 1: Standard FROM/JOIN (handles schema.table and "table")
7771 |         const fromRegex = /(?:FROM|JOIN)\s+(?:(?:"?\w+"?\.)?"?(\w+)"?)/gi;
7772 |         // Pattern 2: Metadata queries (WHERE table_name = '...')
7773 |         const metaRegex = /table_name\s*=\s*'([^']+)'/gi;
7774 | 
7775 |         let match;
7776 |         while ((match = fromRegex.exec(sql)) !== null) {
7777 |             const name = match[1];
7778 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7779 |                 tables.push(name);
7780 |             }
7781 |         }
7782 |         
7783 |         while ((match = metaRegex.exec(sql)) !== null) {
7784 |             const name = match[1];
7785 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7786 |                 tables.push(name);
7787 |             }
7788 |         }
7789 | 
7790 |         return tables;
7791 |     }
7792 | 
7793 |     function convertToCSV(resultObj) {
7794 |         const data = resultObj.data || [];
7795 |         if (!data.length) return '';
7796 |         
7797 |         const tables = extractTableNames(resultObj.sql);
7798 |         const metaHeader = tables.length > 0 ? `# Source Tables: ${tables.join(', ')}\n# Export Date: ${new Date().toISOString()}\n` : '';
7799 | 
7800 |         const headers = Object.keys(data[0]);
7801 |         const rows = data.map(row => 
7802 |             headers.map(header => {
7803 |                 let cell = row[header] === null || row[header] === undefined ? '' : row[header];
7804 |                 if (typeof cell === 'object') cell = JSON.stringify(cell);
7805 |                 return '"' + String(cell).replace(/"/g, '""') + '"';
7806 |             }).join(',')
7807 |         );
7808 |         return metaHeader + [headers.join(','), ...rows].join('\n');
7809 |     }
