    console.log("--- GENERATE FIX (SURGEON) START ---");

    // Full Content - No Truncation as requested
    const filesStr = contextFiles.map((f:any) => 
        `FILE: ${f.path}\n${base64ToText(f.content)}` // <-- NO SUBSTRING()
